module RefModule (
    input clk,
    input reset_n,
    input en,
    input hold,
    output reg [7:0] q);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
        q <= 8'b00000000;
    else if (hold)
        q <= q;
    else if (en)
        q <= q - 1;
end

endmodule
